using UnityEngine;

using DroneSimulator.Config;
using DroneSimulator.Input;
using DroneSimulator.Sensors;

namespace DroneSimulator.Flight
{
    public class AcroFlightController : IFlightController
    {
        private readonly DronePhysicsConfig _physicsConfig;
        private readonly DroneAcroConfig _acroConfig;

        private readonly PIDController _pitchRatePid;
        private readonly PIDController _rollRatePid;
        private readonly PIDController _yawRatePid;

        public AcroFlightController(DronePhysicsConfig physicsConfig, DroneAcroConfig acroConfig)
        {
            _physicsConfig = physicsConfig;
            _acroConfig = acroConfig;

            _pitchRatePid = new PIDController(
                acroConfig.PitchRateGains.x,
                acroConfig.PitchRateGains.y,
                acroConfig.PitchRateGains.z,
                acroConfig.RateErrorSumMax);

            _rollRatePid = new PIDController(
                acroConfig.RollRateGains.x,
                acroConfig.RollRateGains.y,
                acroConfig.RollRateGains.z,
                acroConfig.RateErrorSumMax);

            _yawRatePid = new PIDController(
                acroConfig.YawRateGains.x,
                acroConfig.YawRateGains.y,
                acroConfig.YawRateGains.z,
                acroConfig.RateErrorSumMax);
        }

        public DroneMotorOutput ComputeMotorOutput(DroneSensorData sensorData, DroneInputState inputState)
        {
            // Throttle is already normalised to [0, 1] by the input provider.
            float baseThrottle = inputState.Throttle * _physicsConfig.MaxPropellerForce;

            float pitchCorrection = ComputePitchRateCorrection(inputState.Pitch, sensorData.PitchAngularVelocity);
            float rollCorrection = ComputeRollRateCorrection(inputState.Roll, sensorData.RollAngularVelocity);
            float yawCorrection = ComputeYawRateCorrection(inputState.Yaw, sensorData.YawAngularVelocity);

            DroneMotorOutput output = new DroneMotorOutput();

            // Positive pitchCorrection reduces front motors and increases back motors → nose pitches down.
            // Positive rollCorrection reduces right motors and increases left motors → drone rolls right.
            Debug.LogError($"pitch correction: {pitchCorrection}, roll correction: {rollCorrection}, yaw correction: {yawCorrection}"); 
            output.FrontRightForce = ClampPropellerForce(baseThrottle - pitchCorrection - rollCorrection);
            output.FrontLeftForce = ClampPropellerForce(baseThrottle - pitchCorrection + rollCorrection);
            output.BackRightForce = ClampPropellerForce(baseThrottle + pitchCorrection - rollCorrection);
            output.BackLeftForce = ClampPropellerForce(baseThrottle + pitchCorrection + rollCorrection);

            output.YawTorque = yawCorrection * _physicsConfig.MaxTorque;

            return output;
        }

        // PitchAngularVelocity is in deg/s; positive means the nose is pitching forward (down).
        private float ComputePitchRateCorrection(float pitchStick, float pitchAngularVelocity)
        {
            float desiredPitchRate = pitchStick * _acroConfig.MaxPitchRate;
            float pitchRateError = desiredPitchRate - pitchAngularVelocity;
            return _pitchRatePid.Compute(pitchRateError);
        }

        // RollAngularVelocity is in deg/s; positive means rolling to the right.
        private float ComputeRollRateCorrection(float rollStick, float rollAngularVelocity)
        {
            float desiredRollRate = rollStick * _acroConfig.MaxRollRate;
            float rollRateError = desiredRollRate - rollAngularVelocity;
            return _rollRatePid.Compute(rollRateError);
        }

        // YawAngularVelocity is stored in rad/s (world Y axis); convert to deg/s before comparing.
        private float ComputeYawRateCorrection(float yawStick, float yawAngularVelocityRadPerSec)
        {
            float desiredYawRate = yawStick * _acroConfig.MaxYawRate;
            float actualYawRateDegPerSec = yawAngularVelocityRadPerSec * Mathf.Rad2Deg;
            float yawRateError = desiredYawRate - actualYawRateDegPerSec;
            return _yawRatePid.Compute(yawRateError);
        }

        private float ClampPropellerForce(float force)
        {
            return Mathf.Clamp(force, 0f, _physicsConfig.MaxPropellerForce);
        }
    }
}

using UnityEngine;

using DroneSimulator.Config;
using DroneSimulator.Input;
using DroneSimulator.Sensors;

namespace DroneSimulator.Flight
{
    public class AcroFlightController : IFlightController
    {
        private readonly DronePhysicsConfig _physicsConfig;
        private readonly DroneAcroConfig _acroConfig;

        private readonly PIDController _pitchRatePid;
        private readonly PIDController _rollRatePid;
        private readonly PIDController _yawRatePid;

        public AcroFlightController(DronePhysicsConfig physicsConfig, DroneAcroConfig acroConfig)
        {
            _physicsConfig = physicsConfig;
            _acroConfig = acroConfig;

            _pitchRatePid = new PIDController(
                acroConfig.PitchRateGains.x,
                acroConfig.PitchRateGains.y,
                acroConfig.PitchRateGains.z,
                acroConfig.RateErrorSumMax);

            _rollRatePid = new PIDController(
                acroConfig.RollRateGains.x,
                acroConfig.RollRateGains.y,
                acroConfig.RollRateGains.z,
                acroConfig.RateErrorSumMax);

            _yawRatePid = new PIDController(
                acroConfig.YawRateGains.x,
                acroConfig.YawRateGains.y,
                acroConfig.YawRateGains.z,
                acroConfig.RateErrorSumMax);
        }

        public DroneMotorOutput ComputeMotorOutput(DroneSensorData sensorData, DroneInputState inputState)
        {
            // Throttle is already normalised to [0, 1] by the input provider.
            float baseThrottle = inputState.Throttle * _physicsConfig.MaxPropellerForce;

            float pitchCorrection = ComputePitchRateCorrection(inputState.Pitch, sensorData.PitchAngularVelocity);
            float rollCorrection = ComputeRollRateCorrection(inputState.Roll, sensorData.RollAngularVelocity);
            float yawCorrection = ComputeYawRateCorrection(inputState.Yaw, sensorData.YawAngularVelocity);

            DroneMotorOutput output = new DroneMotorOutput();

            // Positive pitchCorrection reduces front motors and increases back motors → nose pitches down.
            // Positive rollCorrection reduces right motors and increases left motors → drone rolls right.
            output.FrontRightForce = ClampPropellerForce(baseThrottle - pitchCorrection - rollCorrection);
            output.FrontLeftForce = ClampPropellerForce(baseThrottle - pitchCorrection + rollCorrection);
            output.BackRightForce = ClampPropellerForce(baseThrottle + pitchCorrection - rollCorrection);
            output.BackLeftForce = ClampPropellerForce(baseThrottle + pitchCorrection + rollCorrection);

            output.YawTorque = yawCorrection * _physicsConfig.MaxTorque;

            return output;
        }

        // PitchAngularVelocity is in deg/s; positive means the nose is pitching forward (down).
        private float ComputePitchRateCorrection(float pitchStick, float pitchAngularVelocity)
        {
            float desiredPitchRate = pitchStick * _acroConfig.MaxPitchRate;
            float pitchRateError = desiredPitchRate - pitchAngularVelocity;
            return _pitchRatePid.Compute(pitchRateError);
        }

        // RollAngularVelocity is in deg/s; positive means rolling to the right.
        private float ComputeRollRateCorrection(float rollStick, float rollAngularVelocity)
        {
            float desiredRollRate = rollStick * _acroConfig.MaxRollRate;
            float rollRateError = desiredRollRate - rollAngularVelocity;
            return _rollRatePid.Compute(rollRateError);
        }

        // YawAngularVelocity is stored in rad/s (world Y axis); convert to deg/s before comparing.
        private float ComputeYawRateCorrection(float yawStick, float yawAngularVelocityRadPerSec)
        {
            float desiredYawRate = yawStick * _acroConfig.MaxYawRate;
            float actualYawRateDegPerSec = yawAngularVelocityRadPerSec * Mathf.Rad2Deg;
            float yawRateError = desiredYawRate - actualYawRateDegPerSec;
            return _yawRatePid.Compute(yawRateError);
        }

        private float ClampPropellerForce(float force)
        {
            return Mathf.Clamp(force, 0f, _physicsConfig.MaxPropellerForce);
        }
    }
}

using UnityEngine;

namespace DroneSimulator
{
    // A discrete-time PID controller.
    //
    // The controller combines three terms:
    //   P (Proportional) - reacts to the size of the current error.
    //                      A large error produces a large correction. Fast but can overshoot.
    //   I (Integral)     - reacts to how long the error has been accumulating.
    //                      Eliminates the steady-state offset that pure P control leaves behind.
    //   D (Derivative)   - reacts to how quickly the error is changing.
    //                      Dampens oscillations; acts like a brake as the system approaches the target.
    public class PIDController
    {
        private float _proportionalGain;
        private float _integralGain;
        private float _derivativeGain;

        // Running sum of error × dt, clamped to prevent integral windup.
        private float _accumulatedError;
        private readonly float _accumulatedErrorMax;

        // The error value from the previous Compute call, used to estimate the derivative.
        private float _previousError;

        public PIDController(
            float proportionalGain,
            float integralGain,
            float derivativeGain,
            float accumulatedErrorMax = 20f)
        {
            _proportionalGain = proportionalGain;
            _integralGain = integralGain;
            _derivativeGain = derivativeGain;
            _accumulatedErrorMax = accumulatedErrorMax;
        }

        public void UpdateGains(float proportionalGain, float integralGain, float derivativeGain)
        {
            _proportionalGain = proportionalGain;
            _integralGain = integralGain;
            _derivativeGain = derivativeGain;
        }

        // Computes the PID output for the given error.
        // Call once per FixedUpdate; relies on Time.fixedDeltaTime for integration.
        public float Compute(float error)
        {
            // P term: instantaneous response proportional to how far off we are.
            float proportionalOutput = _proportionalGain * error;

            // I term: grow the accumulated error over time and scale by the integral gain.
            // Clamping prevents "integral windup" where a prolonged error makes the
            // integrator so large that the controller overshoots wildly on correction.
            _accumulatedError += error * Time.fixedDeltaTime;
            _accumulatedError = Mathf.Clamp(_accumulatedError, -_accumulatedErrorMax, _accumulatedErrorMax);

            float integralOutput = _integralGain * _accumulatedError;

            // D term: finite-difference estimate of d(error)/dt.
            // Negative d/dt means the error is shrinking — the derivative term subtracts
            // from the output, slowing the correction before it can overshoot.
            float errorChangeRate = (error - _previousError) / Time.fixedDeltaTime;
            _previousError = error;

            float derivativeOutput = _derivativeGain * errorChangeRate;

            return proportionalOutput + integralOutput + derivativeOutput;
        }

        public void Reset()
        {
            _previousError = 0f;
            _accumulatedError = 0f;
        }
    }
}

using UnityEngine;

namespace DroneSimulator
{
    // A discrete-time PID controller.
    //
    // The controller combines three terms:
    //   P (Proportional) - reacts to the size of the current error.
    //                      A large error produces a large correction. Fast but can overshoot.
    //   I (Integral)     - reacts to how long the error has been accumulating.
    //                      Eliminates the steady-state offset that pure P control leaves behind.
    //   D (Derivative)   - reacts to how quickly the error is changing.
    //                      Dampens oscillations; acts like a brake as the system approaches the target.
    public class PIDController
    {
        private float _proportionalGain;
        private float _integralGain;
        private float _derivativeGain;

        // Running sum of error × dt, clamped to prevent integral windup.
        private float _accumulatedError;
        private readonly float _accumulatedErrorMax;

        // The error value from the previous Compute call, used to estimate the derivative.
        private float _previousError;

        // On the very first Compute call _previousError is 0, which would produce a massive
        // derivative spike if the initial error is non-zero. Skip the D term on that first call.
        private bool _isFirstCompute = true;

        public PIDController(
            float proportionalGain,
            float integralGain,
            float derivativeGain,
            float accumulatedErrorMax = 20f)
        {
            _proportionalGain = proportionalGain;
            _integralGain = integralGain;
            _derivativeGain = derivativeGain;
            _accumulatedErrorMax = accumulatedErrorMax;
        }

        public void UpdateGains(float proportionalGain, float integralGain, float derivativeGain)
        {
            _proportionalGain = proportionalGain;
            _integralGain = integralGain;
            _derivativeGain = derivativeGain;
        }

        // Computes the PID output for the given error.
        // Call once per FixedUpdate; relies on Time.fixedDeltaTime for integration.
        public float Compute(float error)
        {
            // P term: instantaneous response proportional to how far off we are.
            float proportionalOutput = _proportionalGain * error;

            // I term: grow the accumulated error over time and scale by the integral gain.
            // Clamping prevents "integral windup" where a prolonged error makes the
            // integrator so large that the controller overshoots wildly on correction.
            _accumulatedError += error * Time.fixedDeltaTime;
            _accumulatedError = Mathf.Clamp(_accumulatedError, -_accumulatedErrorMax, _accumulatedErrorMax);

            float integralOutput = _integralGain * _accumulatedError;

            // D term: finite-difference estimate of d(error)/dt.
            // Negative d/dt means the error is shrinking — the derivative term subtracts
            // from the output, slowing the correction before it can overshoot.
            // Skipped on the first call because _previousError = 0 would cause a false spike.
            float derivativeOutput = 0f;

            if (!_isFirstCompute)
            {
                float errorChangeRate = (error - _previousError) / Time.fixedDeltaTime;
                derivativeOutput = _derivativeGain * errorChangeRate;
            }

            _isFirstCompute = false;
            _previousError = error;


            return proportionalOutput + integralOutput + derivativeOutput;
        }

        public void Reset()
        {
            _isFirstCompute = true;
            _previousError = 0f;
            _accumulatedError = 0f;
        }
    }
}
